```typescript
export type AirCrewState =
  | { status: "none" }
  | { status: "planning"; id: string; members: string[] }
  | { status: "departed"; id: string; departedAt: string };

export type AirCrewCommand =
  | { type: "create"; id: string }
  | { type: "assignMember"; memberId: string }
  | { type: "depart"; at: string };

export type AirCrewEvent =
  | { type: "AirCrewCreated"; id: string }
  | { type: "CrewMemberAssigned"; memberId: string }
  | { type: "AirCrewDeparted"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const airCrewDecider: Decider<AirCrewCommand, AirCrewEvent, AirCrewState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "AirCrewCreated", id: command.id }];
      case "assignMember":
        if (state.status !== "planning") throw new DomainError("NOT_PLANNING");
        if (state.members.includes(command.memberId)) throw new DomainError("DUPLICATE");
        return [{ type: "CrewMemberAssigned", memberId: command.memberId }];
      case "depart":
        if (state.status !== "planning") throw new DomainError("NOT_PLANNING");
        if (state.members.length === 0) throw new DomainError("EMPTY_CREW");
        return [{ type: "AirCrewDeparted", at: command.at }];
      default: { const _n: never = command; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AirCrewCreated":
        return { status: "planning", id: event.id, members: [] };
      case "CrewMemberAssigned":
        if (state.status !== "planning") return state;
        return { ...state, members: [...state.members, event.memberId] };
      case "AirCrewDeparted":
        if (state.status !== "planning") return state;
        return { status: "departed", id: state.id, departedAt: event.at };
      default: { const _n: never = event; return state; }
    }
  },
};
