```typescript
export type AirCrewEvent =
  | { type: "AirCrewCreated"; id: string }
  | { type: "CrewMemberAssigned"; id: string; memberId: string }
  | { type: "AirCrewDeparted"; id: string; at: string }
  | { type: "OtherNoise" };

export interface AirCrewView {
  byId: Record<string, { id: string; memberCount: number; departedAt: string | null }>;
}

export const emptyView: AirCrewView = { byId: {} };

export function project(view: AirCrewView, event: AirCrewEvent): AirCrewView {
  switch (event.type) {
    case "AirCrewCreated":
      return { byId: { ...view.byId, [event.id]: { id: event.id, memberCount: 0, departedAt: null } } };
    case "CrewMemberAssigned": {
      const existing = view.byId[event.id];
      if (!existing) return view;
      return { byId: { ...view.byId, [event.id]: { ...existing, memberCount: existing.memberCount + 1 } } };
    }
    case "AirCrewDeparted": {
      const existing = view.byId[event.id];
      if (!existing) return view;
      return { byId: { ...view.byId, [event.id]: { ...existing, departedAt: event.at } } };
    }
    case "OtherNoise":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
```

A projection is a pure fold over a subset of events into a query-friendly view. Unlike the aggregate state used by the Decider, the view is tailored for reads and ignores events outside its concern.

```typescript
export type GateEvent =
  | { type: "GateRequested"; id: string; airline: string }
  | { type: "GateAssigned"; id: string; gate: string }
  | { type: "GateReleased"; id: string }
  | { type: "WeatherAdvisory"; severity: number };

export interface GateView {
  occupied: Record<string, { assignmentId: string; airline: string }>;
}

export const emptyView: GateView = { occupied: {} };

export function project(view: GateView, event: GateEvent): GateView {
  switch (event.type) {
    case "GateRequested":
      return view;
    case "GateAssigned":
      return { occupied: { ...view.occupied, [event.gate]: { assignmentId: event.id, airline: "unknown" } } };
    case "GateReleased": {
      const gate = Object.keys(view.occupied).find((g) => view.occupied[g].assignmentId === event.id);
      if (!gate) return view;
      const next = { ...view.occupied };
      delete next[gate];
      return { occupied: next };
    }
    case "WeatherAdvisory":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
