export type TurnaroundEvent =
  | { type: "TurnaroundBegun"; id: string; phases: string[] }
  | { type: "PhaseCompleted"; id: string; phase: string }
  | { type: "TurnaroundClosed"; id: string }
  | { type: "AuditNote"; text: string };

export interface TurnaroundBoard {
  active: Record<string, { pending: string[] }>;
}

export const emptyView: TurnaroundBoard = { active: {} };

export function project(view: TurnaroundBoard, event: TurnaroundEvent): TurnaroundBoard {
  switch (event.type) {
    case "TurnaroundBegun":
      return { active: { ...view.active, [event.id]: { pending: [...event.phases] } } };
    case "PhaseCompleted": {
      const row = view.active[event.id];
      if (!row) return view;
      return { active: { ...view.active, [event.id]: { pending: row.pending.filter((p) => p !== event.phase) } } };
    }
    case "TurnaroundClosed": {
      if (!view.active[event.id]) return view;
      const next = { ...view.active };
      delete next[event.id];
      return { active: next };
    }
    case "AuditNote":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
