export type SlotEvent =
  | { type: "SlotGranted"; airport: string; slotId: string }
  | { type: "SlotUsed"; airport: string; slotId: string }
  | { type: "SlotReleased"; airport: string; slotId: string }
  | { type: "UnrelatedOps"; detail: string };

export interface SlotUtilisation {
  perAirport: Record<string, { granted: number; used: number }>;
}

export const emptyView: SlotUtilisation = { perAirport: {} };

function row(view: SlotUtilisation, airport: string): { granted: number; used: number } {
  return view.perAirport[airport] ?? { granted: 0, used: 0 };
}

export function project(view: SlotUtilisation, event: SlotEvent): SlotUtilisation {
  switch (event.type) {
    case "SlotGranted": {
      const r = row(view, event.airport);
      return { perAirport: { ...view.perAirport, [event.airport]: { granted: r.granted + 1, used: r.used } } };
    }
    case "SlotUsed": {
      const r = row(view, event.airport);
      return { perAirport: { ...view.perAirport, [event.airport]: { granted: r.granted, used: r.used + 1 } } };
    }
    case "SlotReleased": {
      const r = row(view, event.airport);
      if (r.granted === 0) return view;
      return { perAirport: { ...view.perAirport, [event.airport]: { granted: r.granted - 1, used: r.used } } };
    }
    case "UnrelatedOps":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
