A Snapshot stores the folded aggregate state along with a schema version. On load, you compare the stored version with the current one and run per-step upgrade functions in order so state layout changes never require rewriting streams. Upgraders are pure.

```typescript
export const CURRENT_VERSION = 3;

export interface AirCrewV1 { id: string; members: string[]; }
export interface AirCrewV2 { id: string; members: string[]; pilotInCommand: string | null; }
export interface AirCrewV3 { id: string; members: string[]; pilotInCommand: string | null; dispatchedAt: string | null; }

export type CurrentState = AirCrewV3;

export interface Snapshot<S> { version: number; state: S; }

function v1Tov2(s: AirCrewV1): AirCrewV2 {
  return { ...s, pilotInCommand: null };
}

function v2Tov3(s: AirCrewV2): AirCrewV3 {
  return { ...s, dispatchedAt: null };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v === 1) { state = v1Tov2(state as AirCrewV1); v = 2; }
  if (v === 2) { state = v2Tov3(state as AirCrewV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`unsupported snapshot version: ${v}`);
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
