export async function appendTurnaround(
  store: EventStore,
  stream: string,
  events: unknown[],
): Promise<bigint> {
  const rev = await store.readRevision(stream);
  const expectedRevision: bigint | "no_stream" = rev === null ? "no_stream" : rev;
  try {
    return await store.appendToStream(stream, events, { expectedRevision });
  } catch (err) {
    const message = err instanceof Error ? err.message : "";
    if (message.includes("WrongExpectedVersion") || message.includes("revision_mismatch")) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
