```typescript
export type AirCrewState = { status: "none" } | { status: "active"; id: string; members: string[] };
export type AirCrewCommand = { type: "create"; id: string } | { type: "assign"; memberId: string };
export type AirCrewEvent = { type: "AirCrewCreated"; id: string } | { type: "CrewMemberAssigned"; memberId: string };

export const initialState: AirCrewState = { status: "none" };

export function evolve(s: AirCrewState, e: AirCrewEvent): AirCrewState {
  switch (e.type) {
    case "AirCrewCreated": return { status: "active", id: e.id, members: [] };
    case "CrewMemberAssigned":
      if (s.status !== "active") return s;
      return { ...s, members: [...s.members, e.memberId] };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: AirCrewCommand, s: AirCrewState): AirCrewEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "AirCrewCreated", id: c.id }];
    case "assign":
      if (s.status !== "active") throw new Error("NOT_ACTIVE");
      return [{ type: "CrewMemberAssigned", memberId: c.memberId }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ revision: bigint; data: AirCrewEvent }[]>;
  appendToStream(stream: string, events: AirCrewEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export async function handle(command: AirCrewCommand, deps: { streamName: string; eventStore: EventStore }): Promise<void> {
  const stored = await deps.eventStore.readStream(deps.streamName);
  const state = stored.reduce<AirCrewState>((s, sv) => evolve(s, sv.data), initialState);
  const events = decide(command, state);
