export interface OutboxRow { id: string; payload: unknown; publishedAt: Date | null; }

export interface TxConn {
  insertOutbox(rows: OutboxRow[]): Promise<void>;
  appendToStream(name: string, events: unknown[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
